import { useState } from "react";
import "./styles/Threads.css";

/* ------------------------------
   Helper: build comment tree
------------------------------ */
function buildCommentTree(comments) {
    const map = new Map();
    const roots = [];

    comments.forEach(c => {
        map.set(c.id, { ...c, replies: [] });
    });

    map.forEach(c => {
        if (c.parentId) {
            const parent = map.get(c.parentId);
            if (parent) {
                parent.replies.push(c);
            }
        } else {
            roots.push(c);
        }
    });

    return roots;
}

/* ------------------------------
   Recursive Comment Item
------------------------------ */
function CommentItem({
                         comment,
                         user,
                         isAdmin,
                         onDelete,
                         toggleReaction,
                         onReply
                     }) {
    const canDelete =
        user && (isAdmin || user.username === comment.username);

    return (
        <li className="comment-item">
            <div className="comment-header">
                <strong>{comment.username}</strong>
                <span className="comment-time">
                    {new Date(comment.createdAt).toLocaleString()}
                </span>
            </div>

            <div className="comment-body">
                <div className="comment-text">{comment.comment}</div>

                <div className="comment-actions">
                    <button
                        className={
                            comment.reactions?.myReaction === "LIKE"
                                ? "reaction-btn active"
                                : "reaction-btn"
                        }
                        onClick={() => toggleReaction(comment, "LIKE")}
                        disabled={!user}
                    >
                        👍 {comment.reactions?.counts?.LIKE || 0}
                    </button>

                    <button
                        className={
                            comment.reactions?.myReaction === "DISLIKE"
                                ? "reaction-btn active dislike"
                                : "reaction-btn dislike"
                        }
                        onClick={() => toggleReaction(comment, "DISLIKE")}
                        disabled={!user}
                    >
                        👎 {comment.reactions?.counts?.DISLIKE || 0}
                    </button>

                    {user && (
                        <button
                            className="reply-btn"
                            onClick={() => onReply(comment.id)}
                        >
                            Reply
                        </button>
                    )}

                    {canDelete && (
                        <button
                            className="delete-btn"
                            onClick={() => onDelete(comment.id)}
                        >
                            Delete
                        </button>
                    )}
                </div>
            </div>

            {comment.replies.length > 0 && (
                <ul className="reply-list">
                    {comment.replies.map(r => (
                        <CommentItem
                            key={r.id}
                            comment={r}
                            user={user}
                            isAdmin={isAdmin}
                            onDelete={onDelete}
                            toggleReaction={toggleReaction}
                            onReply={onReply}
                        />
                    ))}
                </ul>
            )}
        </li>
    );
}

/* ------------------------------
   Main Comment Section
------------------------------ */
export default function CommentSection({
                                           comments,
                                           user,
                                           newComment,
                                           setNewComment,
                                           onSubmit,
                                           onDelete,
                                           refreshComments
                                       }) {
    const role = String(user?.role || "").toUpperCase();
    const isAdmin = role === "ADMIN";

    const [replyTo, setReplyTo] = useState(null);

    const list = Array.isArray(comments) ? comments : [];
    const tree = buildCommentTree(list);

    async function toggleReaction(comment, type) {
        if (!user) return;

        const hasReacted = comment.reactions?.myReaction === type;
        const url = `http://localhost:8080/api/comments/${comment.id}/reactions?username=${user.username}`;

        try {
            if (hasReacted) {
                await fetch(url, { method: "DELETE" });
            } else {
                await fetch(url, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ reactionType: type })
                });
            }

            refreshComments?.();
        } catch (e) {
            console.error("Reaction failed", e);
        }
    }

    const handleSubmit = (e) => {
        e.preventDefault();
        onSubmit(e, replyTo);
        setReplyTo(null);
    };

    return (
        <div className="comments-card">
            <h3>Comments</h3>

            {tree.length === 0 && <p>No comments yet.</p>}

            <ul className="comment-list">
                {tree.map(c => (
                    <CommentItem
                        key={c.id}
                        comment={c}
                        user={user}
                        isAdmin={isAdmin}
                        onDelete={onDelete}
                        toggleReaction={toggleReaction}
                        onReply={setReplyTo}
                    />
                ))}
            </ul>

            {user && replyTo && (
                <p className="replying-indicator">
                    Replying to comment #{replyTo}
                    <button
                        className="cancel-reply-btn"
                        onClick={() => setReplyTo(null)}
                    >
                        Cancel
                    </button>
                </p>
            )}

            <form onSubmit={handleSubmit} className="comment-form">
                <textarea
                    className="textarea"
                    value={newComment}
                    onChange={e => setNewComment(e.target.value)}
                    disabled={!user}
                    placeholder={
                        user
                            ? replyTo
                                ? "Write a reply…"
                                : "Write a comment…"
                            : "Log in to comment"
                    }
                />
                <button
                    className="submit-btn"
                    type="submit"
                    disabled={!user || !newComment.trim()}
                >
                    {replyTo ? "Post Reply" : "Post Comment"}
                </button>
            </form>
        </div>
    );
}
